#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int a,b,c; scanf("%d %d %d", &a, &b, &c);
        int m = a;
        if(b > m) m = b;
        if(c > m) m = c;
        printf("%d\n", m);
    }
    return 0;
}

